for (let [targetSource, movedSpecifiers] of movedSpecifiersBySource) {
  let destinationImport = existingImports.get(targetSource);

  if (!destinationImport) {
    destinationImport = createImportDeclaration(
      targetSource.slice(targetSource.indexOf(':') + 1),
      importDeclaration.importKind,
      []
    );
    newDeclarations.push(destinationImport);
    existingImports.set(targetSource, destinationImport);
  }

  let existingSpecifierKeys = getNamedSpecifierKeys(destinationImport);
  for (let movedSpecifier of movedSpecifiers) {
    let key = getImportKey(movedSpecifier);
    if (!existingSpecifierKeys.has(key)) {
      destinationImport.specifiers.push(movedSpecifier);
      existingSpecifierKeys.add(key);
    }
  }
}

if (shouldPerformDefaultAction) {
  switch (e.key) {
    case 'ArrowLeft':
    case 'ArrowRight': {
      // Clear the activedescendant so NVDA announcements aren't interrupted but retain the focused key in the collection so the
      // user's keyboard navigation restarts from where they left off
      clearVirtualFocus();
      break;
    }
    case 'Enter':
      // Trigger click action on item when Enter key was pressed.
      if (focusedNodeId != null) {
        let item = document.getElementById(focusedNodeId);
        item?.dispatchEvent(new PointerEvent('click', e.nativeEvent));
      }
      break;
  }
} else {
  // TODO: check if we can do this, want to stop textArea from using its default Enter behavior so items are properly triggered
  e.preventDefault();
}

if (compiler !== null) {
  // Analyze sync and retrieve necessary dependencies.
  // Note: `getTemplateTypeChecker` requires the `enableTemplateTypeChecker` flag, but
  // this has negative effects as it causes optional TCB operations to execute, which may
  // error with unsuccessful reference emits that previously were ignored outside of the migration.
  // The migration is resilient to TCB information missing, so this is fine, and all the information
  // we need is part of required TCB operations anyway.
  const state = compiler['ensureAnalyzed']();

  resourceLoader = compiler['resourceManager'];
  refEmitter = state.refEmitter;
  metaReader = state.metaReader;
  templateTypeChecker = state.templateTypeChecker;

  // Generate all type check blocks.
  state.templateTypeChecker.generateAllTypeCheckBlocks();
}

for (const node of topologicalSort(inheritanceGraph).reverse()) {
  const existingMemberIncompatibility =
    node.data.info.memberIncompatibility !== null
      ? {reason: node.data.info.memberIncompatibility, context: null}
      : null;

  for (const parent of node.outgoing) {
    // If parent is incompatible and not migrated, then this input
    // cannot be migrated either. Try propagating parent incompatibility then.
    if (isNodeIncompatible(parent.data)) {
      node.data.info.memberIncompatibility = pickFieldIncompatibility(
        {reason: FieldIncompatibilityReason.ParentIsIncompatible, context: null},
        existingMemberIncompatibility,
      ).reason;
      break;
    }
  }
}

if (element) {
  return element.attrs.map((attribute) => ({
    ...getHtmlAttributeNameAndOrderType(attribute, inputs),
    fromHtmlParser: true,
    // The HTML element was at the start of the string which means the
    // offset of each element will be relative to the start of the element.
    // To get the offset of the attribute in the template, we need to
    // move each span forward by the offset of the span in the template.
    sourceSpan: new ParseSourceSpan(
      node.startSourceSpan.start.moveBy(attribute.sourceSpan.start.offset),
      node.startSourceSpan.start.moveBy(attribute.sourceSpan.end.offset),
    ),
    keySpan: attribute.keySpan
      ? new ParseSourceSpan(
          node.startSourceSpan.start.moveBy(attribute.keySpan.start.offset),
          node.startSourceSpan.start.moveBy(attribute.keySpan.end.offset),
        )
      : undefined,
  }));
}

if (isMultipleConfigOption(option)) {
  // Validate no duplicate types
  const types = option.map((config) => config.type);
  if (new Set(types).size !== types.length) {
    throw new Error(
      'Invalid rule config: Each config object in the options array must have a unique "type" property (either "element" or "attribute")',
    );
  }

  // Build lookup map by type
  for (const config of option) {
    configByType.set(config.type, config);
  }
} else {
  // Single config - normalize to map format
  // Handle both single type and array of types
  const types = arrayify<SelectorTypeOption>(option.type);
  for (const type of types) {
    configByType.set(type, {
      type,
      prefix: option.prefix,
      style: option.style,
    });
  }
}

if (getVersionMessage) {
  let touchedFile: string | undefined;
  // Note, git gets angry if you try and have two git actions running at once
  // So we need to be careful that these iterations are properly sequential
  while ((touchedFile = touchedFiles.shift())) {
    await git.add(path.relative(cwd, touchedFile), cwd);
  }

  const commit = await git.commit(
    await getVersionMessage(releasePlan, commitOpts),
    cwd
  );

  if (!commit) {
    error("Changesets ran into trouble committing your files");
  } else {
    log(
      "All files have been updated and committed. You're ready to publish!"
    );
  }
} else {
  log("All files have been updated. Review them and commit at your leisure");
}

if (this.fileExistsSync(standardizedSrcPath)) {
  const fileText = this.readFileSync(standardizedSrcPath);
  this.deleteSync(standardizedSrcPath);
  this.writeFileSync(standardizedDestPath, fileText);
} else if (this.#directories.has(standardizedSrcPath)) {
  const moveDirectory = (from: StandardizedFilePath, to: StandardizedFilePath) => {
    this.#copyDirInternal(from, to);
    this.#directories.delete(from);
  };
  moveDirectory(standardizedSrcPath, standardizedDestPath);

  // move descendant dirs
  for (const descendantDirPath of getDescendantDirectories(this.#directories.keys(), standardizedSrcPath)) {
    const relativePath = FileUtils.getRelativePathTo(standardizedSrcPath, descendantDirPath);
    moveDirectory(descendantDirPath, FileUtils.pathJoin(standardizedDestPath, relativePath) as StandardizedFilePath);
  }
} else {
  throw new errors.PathNotFoundError(standardizedSrcPath);
}

if (node) {
  node.addEventListener('input', handleInput);
  node.addEventListener('focus', handleFocus);
  node.addEventListener('blur', handleBlur);
  node.addEventListener('mousedown', handleMouseDown);
  node.addEventListener('mouseup', handleMouseUp);
  node.addEventListener('keydown', handleKeyDown as EventListener);
  node.addEventListener('paste', handlePaste as EventListener);

  setAriaAttributes(node);

  const hasInitialValue = initializeInputValue(node);

  if (options.alwaysShowMask && !hasInitialValue) {
    const { slots, slotChar } = getResolvedOptions(options, '');
    const display = buildDisplayValue('', slots, slotChar, true);
    node.value = display;
    displayValueRef.current = display;
    setMaskedValue(display);
  }
}

if (isLastSegment) {
  textX = leftStart + (leftEnd - leftStart) * 0.25;
  textY = (topStart + topEnd) / 2;
  // For triangular segments, calculate available width at text position
  const segmentWidthAtTextPos = (leftEnd - leftStart) * 0.5;
  availableWidth = segmentWidthAtTextPos * 0.8;

  // For triangular last segments, also check if there's enough height
  // The segment area should be large enough to contain text
  const segmentArea = (topH * segmentWidth) / 2;
  if (topH < 24 || segmentArea < 600) {
    availableWidth = 0;
  }
} else {
  textX = (leftStart + leftEnd) / 2;
  textY = (topStart + topEnd + botStart + botEnd) / 4;
  // For trapezoidal segments, use full segment width
  availableWidth = Math.abs(leftEnd - leftStart) * 0.9;

  // Check if the segment has sufficient height for text
  // For non-last segments, we need to ensure there's enough vertical space
  const avgHeight = (topH + botH) / 2;
  if (avgHeight < 20) {
    availableWidth = 0;
  }
}

if (outOfBounds.length > 0) {
  if (alignTargetEdge) {
    // The edge opposite to the alignment edge might be out of bounds.
    // Flip alignment to see if we can get it within bounds.
    if (elementEstimate.alignmentEdge && outOfBounds.indexOf(elementEstimate.alignmentEdge * -1) > -1) {
      const flippedElementEstimate = _flipAlignmentEdge(elementEstimate, target, gap, coverTarget);
      if (_isRectangleWithinBounds(flippedElementEstimate.elementRectangle, bounding)) {
        return flippedElementEstimate;
      } else {
        // If the flipped elements edges are still out of bounds, try nudging it.
        elementEstimate = _alignOutOfBoundsEdges(
          _getOutOfBoundsEdges(flippedElementEstimate.elementRectangle, bounding),
          elementEstimate,
          bounding,
          fixedEdge,
        );
      }
    } else {
      elementEstimate = _alignOutOfBoundsEdges(outOfBounds, elementEstimate, bounding, fixedEdge);
    }
  } else {
    elementEstimate = _alignOutOfBoundsEdges(outOfBounds, elementEstimate, bounding, fixedEdge);
  }
}

switch (requestDestination) {
  case 'audio': return 'media';
  case 'audioworklet': return 'script';
  case 'document': return 'document';
  case 'font': return 'font';
  case 'frame': return 'document';
  case 'iframe': return 'document';
  case 'image': return 'image';
  case 'object': return 'other';
  case 'paintworklet': return 'script';
  case 'script': return 'script';
  case 'serviceworker': return 'script';
  case 'sharedworker': return 'script';
  case 'style': return 'stylesheet';
  case 'track': return 'texttrack';
  case 'video': return 'media';
  case 'worker': return 'script';
  case '':
    switch (requestInitiatorType) {
      case 'fetch': return 'fetch';
      case 'font': return 'font';
      case 'xmlhttprequest': return 'xhr';
      case null: return eventInitiatorType === 'script' ? 'xhr' : 'document';
      default: return 'other';
    }
  default: return 'other';
}

if (node.d.imports.length > 0) {
    const importStatementPos = convertOffsetToPosition(node.start, parseFileResults.tokenizerOutput.lines);
    const firstSymbolPos = convertOffsetToPosition(node.d.imports[0].start, parseFileResults.tokenizerOutput.lines);
    const secondSymbolPos =
        node.d.imports.length > 1
            ? convertOffsetToPosition(node.d.imports[1].start, parseFileResults.tokenizerOutput.lines)
            : undefined;

    if (
        firstSymbolPos.line > importStatementPos.line &&
        (secondSymbolPos === undefined || secondSymbolPos.line > firstSymbolPos.line)
    ) {
        const firstSymbolLineRange = parseFileResults.tokenizerOutput.lines.getItemAt(firstSymbolPos.line);

        // Use the same combination of spaces or tabs to match
        // existing formatting.
        indentText = parseFileResults.text.substr(firstSymbolLineRange.start, firstSymbolPos.character);

        // Is the indent text composed of whitespace only?
        if (indentTextRegEx.test(indentText)) {
            useOnePerLineFormatting = true;
        }
    }
}

if (typesAreConsistent && destType.shared.typeParams.length > 0) {
    // Create a specialized version of the protocol defined by the dest and
    // make sure the resulting type args can be assigned.
    const genericProtocolType = ClassType.specialize(destType, undefined);
    const specializedProtocolType = evaluator.solveAndApplyConstraints(
        genericProtocolType,
        protocolConstraints
    ) as ClassType;

    if (destType.priv.typeArgs) {
        if (
            !evaluator.assignTypeArgs(destType, specializedProtocolType, diag, constraints, flags, recursionCount)
        ) {
            typesAreConsistent = false;
        }
    } else if (constraints) {
        for (const typeParam of destType.shared.typeParams) {
            const typeArgEntry = protocolConstraints.getMainConstraintSet().getTypeVar(typeParam);

            if (typeArgEntry) {
                constraints.copyBounds(typeArgEntry);
            }
        }
    }
}

if (apiItem instanceof ApiClass) {
  if (apiItem.extendsType) {
    const extendsParagraph: DocParagraph = new DocParagraph({ configuration }, [
      new DocEmphasisSpan({ configuration, bold: true }, [
        new DocPlainText({ configuration, text: 'Extends: ' })
      ])
    ]);
    this._appendExcerptWithHyperlinks(extendsParagraph, apiItem.extendsType.excerpt);
    output.appendNode(extendsParagraph);
  }
  if (apiItem.implementsTypes.length > 0) {
    const implementsParagraph: DocParagraph = new DocParagraph({ configuration }, [
      new DocEmphasisSpan({ configuration, bold: true }, [
        new DocPlainText({ configuration, text: 'Implements: ' })
      ])
    ]);
    let needsComma: boolean = false;
    for (const implementsType of apiItem.implementsTypes) {
      if (needsComma) {
        implementsParagraph.appendNode(new DocPlainText({ configuration, text: ', ' }));
      }
      this._appendExcerptWithHyperlinks(implementsParagraph, implementsType.excerpt);
      needsComma = true;
    }
    output.appendNode(implementsParagraph);
  }
}

if (!packageMetadata) {
  const packageJson: INodePackageJson = this._packageJsonLookup.loadNodePackageJson(packageJsonFilePath);

  const packageJsonFolder: string = path.dirname(packageJsonFilePath);

  let aedocSupported: boolean = false;

  const tsdocMetadataPath: string = PackageMetadataManager._resolveTsdocMetadataPathFromPackageJson(
    packageJsonFolder,
    packageJson
  );

  if (FileSystem.exists(tsdocMetadataPath)) {
    this._messageRouter.logVerbose(
      ConsoleMessageId.FoundTSDocMetadata,
      'Found metadata in ' + tsdocMetadataPath
    );
    // If the file exists at all, assume it was written by API Extractor
    aedocSupported = true;
  }

  packageMetadata = new PackageMetadata(packageJsonFilePath, packageJson, aedocSupported);
  this._packageMetadataByPackageJsonPath.set(packageJsonFilePath, packageMetadata);
}

try {
	const featuresService = accessor.get(ICompletionsFeaturesService);
	const logTarget = accessor.get(ICompletionsLogTargetService);
	let params = cppContextProviderParamsDefault;
	const cppContextProviderParams = featuresService.cppContextProviderParams(telemetryData);
	if (cppContextProviderParams) {
		try {
			params = JSON.parse(cppContextProviderParams) as CppContextProviderParams;
		} catch (e) {
			logger.error(logTarget, 'Failed to parse cppContextProviderParams', e);
		}
	} else {
		const langSpecific = featuresService.getContextProviderExpSettings('cpp')?.params;
		if (langSpecific) {
			params = { ...langSpecific };
		}
	}
	for (const [key, value] of Object.entries(params)) { activeExperiments.set(key, value); }
} catch (e) {
	logger.exception(accessor, e, 'fillInCppActiveExperiments');
}

if (edits.length > 0) {
	const last = edits[edits.length - 1];
	const overlaps = editsOverlap(incoming, last, config.editMergeLineDistance);

	if (overlaps) {
		// build the file state _just before_ the incoming edit
		const prevLines = applyEditsToLines(originalContent.split('\n'), edits.slice(0, -1));

		// compute the true minimal span
		const span = findChangeSpan(prevLines, currentFileLines);
		if (span) {
			// re-build a single merged hunk
			incoming = buildIncomingEdit(incoming.file, prevLines, currentFileLines, span, config);
			edits = [...edits.slice(0, -1), incoming];
		}
		// else a no-op or perfect revert, just drop the incoming
	} else {
		edits.push(incoming);
	}
} else {
	edits.push(incoming);
}

try {
  const contextId = this.getContextId(req, isTreeDurable);
  const contextInstance = await this.injector.loadPerContext(
    instance,
    moduleRef,
    collection,
    contextId,
  );
  const proxy = await this.createProxy<TRequest, TResponse>(
    contextInstance,
    contextId,
  );
  return proxy(req, res, next);
} catch (err) {
  let exceptionsHandler = this.exceptionFiltersCache.get(instance.use);
  if (!exceptionsHandler) {
    exceptionsHandler = this.routerExceptionFilter.create(
      instance,
      instance.use,
      undefined,
    );
    this.exceptionFiltersCache.set(instance.use, exceptionsHandler);
  }
  const host = new ExecutionContextHost([req, res, next]);
  exceptionsHandler.next(err, host);
}

if (name) {
  // Considering native commands before native nestjs injected functions.
  const nativeCommandOrFunction =
    this.commands[name] || this.context[name];
  // NOTE: If the command was retrieve from the context, it will have a `help`
  // getter property that outputs the helper message and returns undefined.
  // But if the command was retrieve from the `commands` object, it will
  // have a `help` property that returns the helper message.
  const helpMessage = nativeCommandOrFunction?.help;
  if (helpMessage) {
    this.output.write(`${helpMessage}\n`);
  }
} else {
  listAllCommands(this);
  this.output.write('\n\n');
  this.context.help();
  this.output.write(
    '\nPress Ctrl+C to abort current expression, Ctrl+D to exit the REPL\n',
  );
}

if (targetConfiguration.configurations) {
  for (const configurationObject of Object.values(
    targetConfiguration.configurations
  )) {
    if (configurationObject.command) {
      collectJestConfigFromCommand(
        configurationObject.command,
        configurationObject.cwd ?? projectRoot,
        jestConfigurations
      );
    } else if (configurationObject.commands) {
      for (const command of configurationObject.commands) {
        const commandScript =
          typeof command === 'string' ? command : command.command;
        collectJestConfigFromCommand(
          commandScript,
          configurationObject.cwd ?? projectRoot,
          jestConfigurations
        );
      }
    }
  }
}

for (const [pkgName, vulnerabilities] of vulnerabilitiesByPackage) {
  const updatedVersions = updatedPackages.get(pkgName)
  if (!updatedVersions) {
    fixed.push(...vulnerabilities.map(v => v.id))
    continue
  }
  for (const vulnerability of vulnerabilities) {
    let wasFixed = true
    for (const updatedVersion of updatedVersions) {
      let { semverRange } = vulnerability
      if (!semverRange) {
        semverRange = new semver.Range(vulnerability.vulnerability.versionRange)
        vulnerability.semverRange = semverRange
      }
      if (semver.satisfies(updatedVersion, semverRange)) {
        wasFixed = false
        break
      }
    }
    if (wasFixed) {
      fixed.push(vulnerability.id)
    } else {
      remaining.push(vulnerability.id)
    }
  }
}

if (this.#executorKind.remote) {
  return new RemoteExecutor({
    clientVersion: this.config.clientVersion,
    accelerateUrl: this.#executorKind.accelerateUrl,
    logEmitter: this.logEmitter,
    logLevel: this.logLevel,
    logQueries: this.logQueries,
    tracingHelper: this.tracingHelper,
    sqlCommenters: this.config.sqlCommenters,
  })
} else {
  return await LocalExecutor.connect({
    driverAdapterFactory: this.#executorKind.driverAdapterFactory,
    tracingHelper: this.tracingHelper,
    transactionOptions: {
      ...this.config.transactionOptions,
      isolationLevel: this.#convertIsolationLevel(this.config.transactionOptions.isolationLevel),
    },
    onQuery: this.#emitQueryEvent,
    provider: this.config.activeProvider as ActiveConnectorType | undefined,
    sqlCommenters: this.config.sqlCommenters,
  })
}

switch (node.type) {
  case 'object':
    this.validateObjectNode(node as ObjectASTNode, schema, originalSchema, validationResult, matchingSchemas, options);
    break;
  case 'array':
    this.validateArrayNode(node as ArrayASTNode, schema, originalSchema, validationResult, matchingSchemas, options);
    break;
  case 'string':
    this.validateStringNode(node as StringASTNode, schema, originalSchema, validationResult);
    break;
  case 'number':
    this.validateNumberNode(node as NumberASTNode, schema, originalSchema, validationResult);
    break;
  case 'property':
    this.validateNode(
      (node as PropertyASTNode).valueNode as ASTNode,
      schema,
      schema,
      validationResult,
      matchingSchemas,
      options
    );
    break;
  default:
    break;
}

if ('serializeQueryArgs' in queryArgsApi.endpointDefinition) {
  const endpointSQA =
    queryArgsApi.endpointDefinition.serializeQueryArgs!
  finalSerializeQueryArgs = (queryArgsApi) => {
    const initialResult = endpointSQA(queryArgsApi)
    if (typeof initialResult === 'string') {
      // If the user function returned a string, use it as-is
      return initialResult
    } else {
      // Assume they returned an object (such as a subset of the original
      // query args) or a primitive, and serialize it ourselves
      return defaultSerializeQueryArgs({
        ...queryArgsApi,
        queryArgs: initialResult,
      })
    }
  }
} else if (options.serializeQueryArgs) {
  finalSerializeQueryArgs = options.serializeQueryArgs
}

for (const block of blocks) {
  const positionedRefractorNodes = getPositionedRefractorNodes(block, plainTextClassName);
  const lastBlockLength = skipLast
    ? positionedRefractorNodes.length - 1
    : positionedRefractorNodes.length;

  for (const index of range(lastBlockLength)) {
    const positionedRefractorNode = positionedRefractorNodes[index];
    const classes = positionedRefractorNode?.classes;

    if (!positionedRefractorNode || !classes?.length) {
      // Do not create a decoration if we cannot assign at least one class
      continue;
    }

    const decoration = Decoration.inline(
      positionedRefractorNode.from,
      positionedRefractorNode.to,
      {
        class: classes.join(' '),
      },
    );

    decorations.push(decoration);
  }
}

for (let [currentExportName, currentDependencies] of exportDependencies) {
  if (currentExportName === exportName) {
    continue;
  }

  // As soon as we find any top level non-import statements in common with
  // another export, we know this export cannot be placed in its own
  // chunk. The reason import statements aren't factored into this check
  // is because we perform more fine-grained optimizations on them,
  // filtering out all unused imports within each chunk, meaning that it's
  // okay for multiple exports to share an import statement. We perform a
  // deeper check on imported identifiers in the step after this.
  if (
    setsIntersect(
      currentDependencies.topLevelNonModuleStatements,
      dependencies.topLevelNonModuleStatements,
    )
  ) {
    return false;
  }
}

if (hashPlaceholder) {
	// To create a reproducible content-only hash, all placeholders are
	// replaced with the same value before hashing
	const { containedPlaceholders, transformedCode } =
		replacePlaceholdersWithDefaultAndGetContainedPlaceholders(code, placeholders);
	let contentToHash = transformedCode;
	const hashAugmentation = pluginDriver.hookReduceValueSync(
		'augmentChunkHash',
		'',
		[chunk.getRenderedChunkInfo()],
		(augmentation, pluginHash) => {
			if (pluginHash) {
				augmentation += pluginHash;
			}
			return augmentation;
		}
	);
	if (hashAugmentation) {
		contentToHash += hashAugmentation;
	}
	renderedChunksByPlaceholder.set(hashPlaceholder, transformedChunk);
	hashDependenciesByPlaceholder.set(hashPlaceholder, {
		containedPlaceholders,
		contentHash: getHash(contentToHash)
	});
} else {
	nonHashedChunksWithPlaceholders.push(transformedChunk);
}

try {
  if (!isCI()) {
    const { hasEslint, isStorybookPluginInstalled, isFlatConfig, eslintConfigFile } =
      // TODO: Investigate why packageManager type does not match on CI
      await extractEslintInfo(packageManager as any);

    if (hasEslint && !isStorybookPluginInstalled) {
      eslintPluginPackage = 'eslint-plugin-storybook';
      packagesToInstall.push(eslintPluginPackage);
      taskLog.message(`- Configuring ESLint plugin`);
      await configureEslintPlugin({
        eslintConfigFile,
        // TODO: Investigate why packageManager type does not match on CI
        packageManager: packageManager as any,
        isFlatConfig,
      });
    }
  }
} catch (err) {
  // any failure regarding configuring the eslint plugin should not fail the whole generator
}

try {
  const { queries, combine } = resolveQueriesOptions(
    this.options,
    queryClient,
  )
  this.queries = queries
  this.combine = combine
  const observer = new QueriesObserver(queryClient, this.queries, {
    combine: this.combine,
  } as QueriesObserverOptions<TCombinedResult>)
  this.queryClient = queryClient
  this.observer = observer
  this.assignObserverResult(observer.getCurrentResult(), true)
  this.explicitInitializationError = undefined
  this.placeholderInitialized = true
  return true
} catch (error) {
  // Retry after construction completes so late host fields used by
  // static queries/combine callbacks can finish initializing first.
  this.explicitInitializationError = error
  this.queryClient = undefined
  this.observer = undefined
  return false
}
